class StorageManager{constructor(){this._storage=null}init(){if(window._firebaseConfigured)try{this._storage=firebase.storage(),console.info("[Storage] Initialized")}catch(e){console.warn("[Storage] Init error:",e)}}get _uid(){var e;return((e=window.authManager)==null?void 0:e.uid)||null}get _ready(){return!!(this._storage&&this._uid)}async uploadRecording(e,r){if(!this._ready)return null;const a=`users/${this._uid}/recordings/${r}`;try{const t=this._storage.ref(a),n={contentType:e.type||"audio/webm"},s=await(await t.put(e,n)).ref.getDownloadURL();return console.info("[Storage] Uploaded:",r),s}catch(t){return console.warn("[Storage] Upload error:",t),null}}async getRecordingURL(e){if(!this._ready)return null;try{return await this._storage.ref(`users/${this._uid}/recordings/${e}`).getDownloadURL()}catch(r){return null}}async listRecordings(){if(!this._ready)return[];try{const e=await this._storage.ref(`users/${this._uid}/recordings`).listAll();return await Promise.all(e.items.map(async r=>({name:r.name,url:await r.getDownloadURL()})))}catch(e){return console.warn("[Storage] List error:",e),[]}}async deleteRecording(e){if(this._ready)try{await this._storage.ref(`users/${this._uid}/recordings/${e}`).delete(),console.info("[Storage] Deleted:",e)}catch(r){console.warn("[Storage] Delete error:",r)}}generateFilename(e="rec"){const r=new Date().toISOString().replace(/[:.]/g,"-").slice(0,19);return`${e}_${r}.webm`}}window.storageManager=new StorageManager;
